public int findDuplicate(int[] nums) {
    int slow = nums[0], fast = nums[0];

    // Phase 1: detect cycle
    do {
        slow = nums[slow];
        fast = nums[nums[fast]];
    } while (slow != fast);

    // Phase 2: find entrance
    slow = nums[0];
    while (slow != fast) {
        slow = nums[slow];
        fast = nums[fast];
    }

    return slow;
}

public int findDuplicate(int[] nums) {
    int lo = 1, hi = nums.length - 1;

    while (lo < hi) {
        int mid = (lo + hi) / 2;
        int count = 0;
        for (int n : nums) if (n <= mid) count++;
        if (count > mid) hi = mid;
        else lo = mid + 1;
    }

    return lo;
}

